        "function wrapper() { for (var a in {}) console.log(a) }",
    );
    test(
        "function wrapper() { var x = a; for (var a in x) console.log(a) }",
        "function wrapper() { for (var a in a) console.log(a) }",
    );
    test(
        "function wrapper() { var x = a; for (let a in x) console.log(a) }",
        "function wrapper() { var x = a; for (let a in x) console.log(a) }",
    );
